                d-dt-geracao-arq    = DATE ( SUBSTRING(c-linha, 18 , 2 ) + "/" + SUBSTRING(c-linha, 16 , 2 ) + "/" + SUBSTRING(c-linha, 14, 2)  ) 
                c-hr-geracao-arq    = SUBSTRING(c-linha, 20 , 06  )
                c-cnpj-transmissor  = SUBSTRING(c-linha, 26 , 14 )
                c-cnpj-receptor     = SUBSTRING(c-linha, 40 , 14 )
                .

        END.

        IF SUBSTRING ( c-linha , 1 , 3 ) EQ "AE1" THEN DO:

            ASSIGN
            au-num-nfe     = SUBSTRING(c-linha, 04, 06  )
            au-serie       = SUBSTRING(c-linha, 10, 04  )
            au-data-nfe    = DATE ( SUBSTRING(c-linha, 18 , 2 ) + "/" + SUBSTRING(c-linha, 16 , 2 ) + "/" + SUBSTRING(c-linha, 14, 2)  ) 
            au-val-nfe     = dec(SUBSTRING(c-linha, 23, 17  ))
            au-nat-oper    = SUBSTRING(c-linha, 41, 05  )
            au-data-prev   = DATE ( SUBSTRING(c-linha, 95 , 2 ) + "/" + SUBSTRING(c-linha, 93 , 2 ) + "/" + SUBSTRING(c-linha, 91, 2)  ) 
            .


        END.

        IF SUBSTRING (c-linha , 1 , 3 ) EQ "AE2" THEN DO:
            
            ASSIGN
            ad-num-ped         = SUBSTRING(c-linha, 07, 12  )
            ad-cod-item        = SUBSTRING(c-linha, 19, 30  )
            ad-qde-it-nfe      = dec(SUBSTRING(c-linha, 49, 09  ))
            ad-unid-med        = SUBSTRING(c-linha, 58, 02  )
            ad-ncm             = int(SUBSTRING(c-linha, 60, 10  ))
            ad-val-unit-item   = dec(SUBSTRING(c-linha, 74, 12  ))
            .
        END.

        IF SUBSTRING (c-linha , 1 , 3 ) EQ "AE4" THEN DO:
            
            ASSIGN
            aq-preco-tot-merc = DEC(SUBSTRING(c-linha, 116, 12  ))
            .

            CREATE tt-entr-forn.
            ASSIGN
                   tt-entr-forn.d-dt-geracao-arq     =   d-dt-geracao-arq   
                   tt-entr-forn.c-hr-geracao-arq     =   c-hr-geracao-arq   
                   tt-entr-forn.c-cnpj-transmissor   =   c-cnpj-transmissor 
                   tt-entr-forn.c-cnpj-receptor      =   c-cnpj-receptor    
                   tt-entr-forn.c-cod-transmissor    =   c-cod-transmissor  
                   tt-entr-forn.au-num-nfe           =   au-num-nfe         
                   tt-entr-forn.au-serie             =   au-serie           
                   tt-entr-forn.au-data-nfe          =   au-data-nfe        
                   tt-entr-forn.au-val-nfe           =   au-val-nfe         
                   tt-entr-forn.au-nat-oper          =   au-nat-oper        
                   tt-entr-forn.au-data-prev         =   au-data-prev       
                   tt-entr-forn.ad-num-ped           =   ad-num-ped         
                   tt-entr-forn.ad-cod-item          =   ad-cod-item        
                   tt-entr-forn.ad-qde-it-nfe        =   ad-qde-it-nfe      
                   tt-entr-forn.ad-unid-med          =   ad-unid-med        
                   tt-entr-forn.ad-ncm               =   ad-ncm             
                   tt-entr-forn.ad-val-unit-item     =   ad-val-unit-item   
                   tt-entr-forn.aq-preco-tot-merc    =   aq-preco-tot-merc.
        END.
        
    END .
    INPUT CLOSE.

   
END.

